```solidity
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract SimpleCrowdsale {
    address payable public wallet;
    uint256 public rate;
    uint256 public weiRaised;
    mapping(address => uint256) public tokensPurchased;

    event TokensPurchased(address indexed purchaser, address indexed beneficiary, uint256 value, uint256 amount);

    constructor(uint256 _rate, address payable _wallet) {
        require(_rate > 0, "Rate cannot be zero");
        require(_wallet != address(0), "Wallet address cannot be zero");

        rate = _rate;
        wallet = _wallet;
    }

    function getTokensPurchased(address _addr) public view returns (uint256) {
        return tokensPurchased[_addr];
    }

    function buyTokens() public payable {
        require(msg.value > 0, "Value must be greater than zero");
        uint256 weiAmount = msg.value;
        uint256 tokens = weiAmount * rate;

        // Transfer funds to the wallet
        wallet.transfer(msg.value);

        // Update state
        weiRaised += weiAmount;
        tokensPurchased[msg.sender] += tokens;

        emit TokensPurchased(msg.sender, msg.sender, weiAmount, tokens);
    }
}
```

This implementation ensures the contract is correct, secure, and reasonably gas-efficient while adhering to the specified constraints.
